CREATE TABLE IF NOT EXISTS reviews (id SERIAL PRIMARY KEY, author_name VARCHAR(255) NOT NULL, author_city VARCHAR(100), text TEXT NOT NULL, product_name VARCHAR(255), is_active BOOLEAN DEFAULT true, is_featured BOOLEAN DEFAULT false, sort_order INT DEFAULT 0, created_at TIMESTAMPTZ DEFAULT NOW()); CREATE TABLE IF NOT EXISTS orders (id SERIAL PRIMARY KEY, name VARCHAR(255) NOT NULL, phone VARCHAR(50), email VARCHAR(255), message TEXT, service VARCHAR(255), product_id INT, product_name VARCHAR(255), status VARCHAR(50) DEFAULT 'new', source VARCHAR(100) DEFAULT 'website', manager_note TEXT, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW()); ALTER TABLE orders ADD CONSTRAINT fk_orders_product FOREIGN KEY (product_id) REFERENCES products(id);